// MARK: - Swizzling Setup (Example - Use with caution in production)

/// This class demonstrates how to swizzle `viewDidAppear` to automatically log screen views.
/// SWIZZLING SHOULD BE USED WITH EXTREME CAUTION AND THOROUGH TESTING IN PRODUCTION.
/// It can lead to subtle bugs and crashes if not implemented correctly.
class AnalyticsSwizzler {
    static let shared = AnalyticsSwizzler()

    private init() {}

    func enableScreenViewTracking() {
        let originalSelector = #selector(UIViewController.viewDidAppear(_:))
        let swizzledSelector = #selector(UIViewController.swizzled_viewDidAppear(_:))

        guard let originalMethod = class_getInstanceMethod(UIViewController.self, originalSelector),
              let swizzledMethod = class_getInstanceMethod(UIViewController.self, swizzledSelector) else {
            NSLog("‼️ AnalyticsSwizzler: Could not find methods for swizzling.")
            return
        }

        let didAddMethod = class_addMethod(UIViewController.self,
                                           originalSelector,
                                           method_getImplementation(swizzledMethod),
                                           method_getTypeEncoding(swizzledMethod))

        if didAddMethod {
            class_replaceMethod(UIViewController.self,
                                swizzledSelector,
                                method_getImplementation(originalMethod),
                                method_getTypeEncoding(originalMethod))
            NSLog("✅ AnalyticsSwizzler: viewDidAppear swizzled successfully (added method).")
        } else {
            method_exchangeImplementations(originalMethod, swizzledMethod)
            NSLog("✅ AnalyticsSwizzler: viewDidAppear swizzled successfully (exchanged implementations).")
        }
    }
}

